package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetCommentMarker_DefaultNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getCommentMarker());
    }

    @Test
    void testGetCommentMarker_WithCommentMarkerChar() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        Character commentMarker = format.getCommentMarker();
        assertNotNull(commentMarker);
        assertEquals(Character.valueOf('#'), commentMarker);

        // additionally verify via reflection that the private field is set correctly
        Field field = CSVFormat.class.getDeclaredField("commentMarker");
        field.setAccessible(true);
        Character fieldValue = (Character) field.get(format);
        assertEquals(Character.valueOf('#'), fieldValue);
    }

    @Test
    void testGetCommentMarker_WithCommentMarkerCharacterObject() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(Character.valueOf(';'));
        Character commentMarker = format.getCommentMarker();
        assertNotNull(commentMarker);
        assertEquals(Character.valueOf(';'), commentMarker);

        // additionally verify via reflection that the private field is set correctly
        Field field = CSVFormat.class.getDeclaredField("commentMarker");
        field.setAccessible(true);
        Character fieldValue = (Character) field.get(format);
        assertEquals(Character.valueOf(';'), fieldValue);
    }
}
